render.css:
.circle-container { position: relative; display: flex; align-items: center; justify-content: center; margin-top: auto; margin-bottom: auto; }
.circle-svg { transform: rotate(-90deg); }
.circle-bg { fill: none; stroke: var(--ct-surface-2); stroke-width: 8; }
.circle-progress { fill: none; stroke: var(--ct-text-strong); stroke-width: 8; stroke-linecap: round; transition: stroke-dashoffset 600ms ease; }
.circle-text { position: absolute; text-align: center; }
.circle-text .percent { display: block; font-size: 32px; font-weight: 700; color: var(--ct-text-primary); }
.circle-text .label { font-size: 12px; color: var(--ct-text-muted); font-weight: 500; }
